}
```

TASK 2 — ImageUploader.tsx:
Replace the inner try block (lines 38-58):
```ts
try {
  const { error } = await Promise.race([
    supabase.storage.from('images').upload(path, file, {
      cacheControl: '3600',
      upsert: false,
    }),
    new Promise<never>((_, reject) =>
      setTimeout(() => reject(new Error('Timeout завантаження')), 10_000)
    ),
  ]);

  if (error) {
    console.error('[ImageUploader] upload error', error);
    setPreview(value ?? null);
